CREATE OR REPLACE FUNCTION users.add_contact_to_user_struct(_user_struct_id bigint, _contact json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _type_id bigint;
    _contact_id bigint;
BEGIN

    RAISE NOTICE 'add_contact_to_user_struct';

    -- check if type exists
    IF NOT EXISTS(SELECT * FROM contact_type WHERE name = _contact ->> 'type') THEN
        RAISE EXCEPTION 'No contact_type with name % found', _contact ->> 'type' USING ERRCODE = 'T8AZ0';
    end if;

    -- get type id
    SELECT * FROM contact_type WHERE name = _contact ->> 'type' LIMIT 1 INTO _type_id;

    -- check contact not already exists
    IF EXISTS(SELECT * FROM contact WHERE value = _contact ->> 'value' AND type_id = _type_id AND user_struct_id = _user_struct_id) THEN
        RAISE EXCEPTION 'contact already exists with name %', _contact ->> 'name' USING ERRCODE = 'T9AZ1';
    end if;

    -- create contact
    INSERT INTO contact (type_id, name, user_struct_id, value, maintenance_notification, marketing_notification) VALUES (
        _type_id,
        _contact ->> 'name',
        _user_struct_id,
        _contact ->> 'value',
        (_contact ->> 'maintenance_notification')::bool,
        (_contact ->> 'marketing_notification')::bool
    ) RETURNING id INTO _contact_id;

    RETURN _contact_id;
END;
$function$

CREATE OR REPLACE FUNCTION users.add_page_to_role(_role_id bigint, _page_name character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _page page%rowtype;
    _role role%rowtype;
BEGIN

    -- check page exists
    IF NOT EXISTS (SELECT * FROM page p WHERE p.name = _page_name) THEN
        RAISE EXCEPTION 'No page with name % found', _page_name USING ERRCODE = 'T2AZ0';
    end if;

    -- check role exists
    IF NOT EXISTS (SELECT * FROM role WHERE id = _role_id) THEN
        RAISE EXCEPTION 'No role with id % found', _role_id USING ERRCODE = 'T3AZ0';
    end if;

    -- check mapping does not already exist
    IF EXISTS (SELECT * FROM role_page rp WHERE rp.page_name = _page_name AND rp.role_id = _role_id) THEN
        RAISE EXCEPTION 'Page with name % already exist for role %', _page_name, _role_id USING ERRCODE = 'T1AZ1';
    end if;

    -- check if page is protected and role is default
    SELECT * FROM page p WHERE p.name = _page_name INTO _page;
    SELECT * FROM role WHERE id = _role_id INTO _role;
    IF NOT (_role.customer_id IS NULL OR (_page.selectable = true AND _page.protected = false)) THEN
        RAISE EXCEPTION 'Page with name % is protected and cannot be assigned to customer role %', _page_name, _role_id USING ERRCODE = 'T1AZ2';
    end if;

    -- check if not already entailed
    IF NOT EXISTS( SELECT e.name FROM get_page_table_by_role(_role_id) e WHERE e.name = _page_name) THEN

        -- insert mapping
        INSERT INTO role_page (role_id, page_name) VALUES (_role_id, _page_name);
    end if;

    -- delete pages entailed by this one
    DELETE from role_page rp WHERE rp.role_id = _role_id AND rp.page_name IN (
        SELECT child FROM get_entailed_pages(_page_name)
    );
END;
$function$

CREATE OR REPLACE FUNCTION users.add_resource_access_to_customer_group(_resource json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check already exists
    IF EXISTS (SELECT * FROM customer_group_resources WHERE customer_group_id = (_resource ->> 'customer_group_id')::bigint AND resource = _resource ->> 'resource' AND access_type = _resource ->> 'access_type') THEN
        RAISE EXCEPTION 'CustomerGroupResource (% % %) already exists', _resource ->> 'customer_group_id', _resource ->> 'resource', _resource ->> 'access_type' USING ERRCODE = 'T7AZ1';
    end if;

    INSERT INTO customer_group_resources (customer_group_id, resource, access_type) VALUES ((_resource ->> 'customer_group_id')::bigint, _resource ->> 'resource', _resource ->> 'access_type');
END;
$function$

CREATE OR REPLACE FUNCTION users.add_resource_access_to_page(_page_name character varying, _resource json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check if page exists
    IF NOT EXISTS (SELECT * FROM page WHERE name = _page_name) THEN
        RAISE EXCEPTION 'No page with name % found', _page_name USING ERRCODE = 'T2AZ0';
    end if;

    -- check already exists
    IF EXISTS (SELECT * FROM resource_access WHERE page_name = _page_name AND resource = _resource ->> 'resource' AND access_type = _resource ->> 'access_type') THEN
        RAISE EXCEPTION 'ResourceAccess (% % %) already exists', _page_name, _resource ->> 'resource', _resource ->> 'access_type' USING ERRCODE = 'T1AZ1';
    end if;

    INSERT INTO resource_access (page_name, resource, access_type) VALUES (_page_name, _resource ->> 'resource', _resource ->> 'access_type');
END;
$function$

CREATE OR REPLACE FUNCTION users.build_role(_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    pages json[];
    result json;
BEGIN

    -- get pages as json array
    SELECT array(
        SELECT get_page(p.name)
        FROM role_page rp
        LEFT JOIN page p ON rp.page_name = p.name
        WHERE rp.role_id = _id
    ) into pages;

    -- compose global json
    SELECT INTO result json_agg(x) -> 0 FROM (
        SELECT id, name, customer_id, color, pages FROM role WHERE id = _id LIMIT 1
    ) x;

    RETURN result;
END;
$function$

CREATE OR REPLACE FUNCTION users.check_user(_email character varying)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user_struct_id bigint;
BEGIN

    RAISE NOTICE 'check_user';

    -- check if user exists
    IF NOT EXISTS(SELECT * FROM "user" WHERE email = _email) THEN
        RETURN false;
    end if;

    -- if exist active_user_struct
    IF EXISTS(SELECT * FROM "user" u INNER JOIN user_struct us ON u.active_user_struct_id = us.id WHERE email = _email) THEN
        RETURN false;
    end if;

    -- check if has user_structs available
    IF NOT EXISTS(SELECT id FROM user_struct WHERE primary_email = _email) THEN

        -- delete user bc it has no user_structs
        DELETE from "user" WHERE email = _email;

        RETURN true; --user has been deleted
    end if;

    -- choose first user_structs available
    SELECT id FROM user_struct WHERE primary_email = _email LIMIT 1 INTO _user_struct_id;

    -- update
    UPDATE "user" SET active_user_struct_id = _user_struct_id WHERE email = _email;

    RETURN false; --user was not deleted
END;
$function$

CREATE OR REPLACE FUNCTION users.delete_page(_name character varying)
