CREATE OR REPLACE FUNCTION users.delete_user_struct(_user_struct_id bigint)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    _email varchar;
    _count int;
    _next bigint;
BEGIN

    RAISE NOTICE 'delete_user_struct %', _user_struct_id ;

    -- check if user_struct exists
    IF NOT EXISTS(SELECT * FROM user_struct WHERE id = _user_struct_id) THEN
        RAISE EXCEPTION 'No user_struct with id %d found', _user_struct_id USING ERRCODE = 'T5AZ0';
    end if;

    -- get email
    SELECT primary_email From user_struct WHERE id = _user_struct_id INTO _email;


    IF EXISTS(SELECT * FROM "user" WHERE active_user_struct_id = _user_struct_id) THEN

        -- count
        SELECT INTO _count count(*) FROM user_struct WHERE primary_email = _email;

        IF _count > 1 THEN

            -- get next
            SELECT INTO _next id FROM user_struct WHERE primary_email = _email AND id <> _user_struct_id LIMIT 1;

            -- update
            UPDATE "user" SET active_user_struct_id = _next WHERE email = _email;

        ELSE

            -- update
            UPDATE "user" SET active_user_struct_id = NULL WHERE email = _email;

        END IF;

    END IF;

    -- delete
    DELETE FROM user_struct WHERE id = _user_struct_id;

    -- check user (set new user_struct as active or delete user)
    RETURN check_user(_email);
    RETURN false;

END;
$function$

