        SELECT array (
            SELECT get_page_protected(name) FROM (
                SELECT name FROM page_protected where parent IS NULL
            ) as pages
        ) into tmp;

    ELSE

        SELECT array (
            SELECT get_page_unprotected(name) FROM (
                SELECT name FROM page_unprotected where parent IS NULL
