CREATE OR REPLACE FUNCTION users.get_all_resource_access_by_page(_name character varying)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    tmp json[];
    result json;
BEGIN

    -- check if page exists
    IF NOT EXISTS (SELECT * FROM page WHERE name = _name) THEN
        RAISE EXCEPTION 'No page with name % found', _name USING ERRCODE = 'T2AZ0';
    end if;

    -- select resource_access of specified page + all entailed pages
    SELECT array( SELECT json_build_object('resource', resource, 'access_type', access_type) FROM
        (
            (
                SELECT resource, access_type
                FROM get_entailed_pages(_name) ep
                INNER JOIN resource_access ra ON ep.child = ra.page_name
            )
            UNION
            (
                SELECT resource, access_type
                FROM resource_access
                WHERE page_name = _name
            )
        ) x
    ) into tmp;

    -- get global json
    SELECT INTO result to_json(tmp);

    RETURN result;
END;
$function$

