CREATE OR REPLACE FUNCTION users.get_contact(_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _contact json;
BEGIN

    -- raise exception if not found
    IF NOT EXISTS(SELECT * FROM contact WHERE id = _id) THEN
        RAISE EXCEPTION 'No contact with id % found', _id USING ERRCODE = 'T9AZ0';
    end if;

    -- get contact
    SELECT INTO _contact json_agg(x) -> 0 FROM (
        SELECT c.id, ct.name as type, c.name, c.maintenance_notification, c.marketing_notification, c.value, c.user_struct_id FROM contact c LEFT JOIN contact_type ct ON c.type_id = ct.id WHERE c.id = _id LIMIT 1
    ) x;

    -- return json
    RETURN _contact;

END;
$function$

