CREATE OR REPLACE FUNCTION users.get_full_pages_subtrees(pages character varying[])
 RETURNS TABLE(name character varying, parent character varying, protected boolean, selectable boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
    assigned_page varchar;
    entailed_page varchar;
    next_page RECORD;
BEGIN

    FOREACH assigned_page IN ARRAY pages
        LOOP

            -- return page itself
            SELECT * FROM page p WHERE p.name = assigned_page INTO next_page;
            name := next_page.name;
            parent := next_page.parent;
            protected := next_page.protected;
            selectable := next_page.selectable;
            RETURN NEXT;

            -- select all pages that are entailed
            FOR entailed_page IN (
                SELECT child FROM get_entailed_pages(assigned_page)
            )
                LOOP

                    -- get page
                    SELECT * FROM page p WHERE p.name = entailed_page INTO next_page;
                    name := next_page.name;
                    parent := next_page.parent;
                    protected := next_page.protected;
                    selectable := next_page.selectable;

                    -- return entry
                    RETURN NEXT;
                end loop;
        END LOOP;

END;
$function$

CREATE OR REPLACE FUNCTION users.get_leaf_pages(pages character varying[])
 RETURNS TABLE(name character varying, parent character varying, protected boolean, selectable boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
    assigned_page varchar;
    entailed_page varchar;
    next_page RECORD;
BEGIN

    FOREACH assigned_page IN ARRAY pages
    LOOP

        -- select all pages that are entailed and are leaves
        FOR entailed_page IN (
            SELECT child FROM get_entailed_pages(assigned_page)
            WHERE is_page_leaf(child)
        )
        LOOP

            -- get page
            SELECT * FROM page p WHERE p.name = entailed_page INTO next_page;
            name := next_page.name;
            parent := next_page.parent;
            protected := next_page.protected;
            selectable := next_page.selectable;

            -- return entry
            RETURN NEXT;
        end loop;
    END LOOP;

END;
$function$

