CREATE OR REPLACE FUNCTION users.get_page(_name character varying)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    resources json;
    children json[];
    result json;
BEGIN

    -- if page not found -> error
    IF NOT EXISTS (SELECT * FROM page WHERE name = _name) THEN
        RAISE EXCEPTION 'No page with name % found', _name USING ERRCODE = 'T2AZ0';
    end if;

    -- get resources as json array
    SELECT into resources json_agg(x) FROM (
        SELECT resource, access_type from resource_access WHERE page_name = _name
    ) x;

    -- get pages as array
    -- recursive call to create tree from page
    SELECT array(
        SELECT get_page(p.name) FROM page p WHERE p.parent = _name
    ) into children;

    -- get global json
    SELECT INTO result json_agg(x) -> 0 FROM (
        SELECT page.*, resources, children FROM page WHERE name = _name LIMIT 1
    ) x;

    RETURN result;
END;
$function$

CREATE OR REPLACE FUNCTION users.get_page_protected(_name character varying)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    resources json;
    children json[];
    result json;
BEGIN

    -- if page not found -> error
    IF NOT EXISTS (SELECT * FROM page_protected WHERE name = _name ) THEN
        RAISE EXCEPTION 'No page with name % found', _name USING ERRCODE = 'T2AZ0';
    end if;

    -- get resources as json array
    SELECT into resources json_agg(x) FROM (
        SELECT resource, access_type from resource_access WHERE page_name = _name
    ) x;

    -- get all children that have protected children or are protected
    -- recursive call to create tree from page
    SELECT array(
        SELECT get_page_protected(p.name) FROM page_protected p WHERE p.parent = _name
    ) into children;

    -- get global json
    SELECT INTO result json_agg(x) -> 0 FROM (
        SELECT page.*, resources, children FROM page WHERE name = _name LIMIT 1
    ) x;

    RETURN result;
END;
$function$

