CREATE OR REPLACE FUNCTION users.get_role(_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    result json;
BEGIN

    RAISE NOTICE 'get_role';

    -- check if exist
    IF NOT EXISTS (SELECT * FROM role WHERE id = _id) THEN
        RAISE EXCEPTION 'No role with id % found', _id USING ERRCODE = 'T3AZ0';
    end if;

    -- get role json
    SELECT INTO result build_role(_id);

    RETURN result;
END;
$function$

CREATE OR REPLACE FUNCTION users.get_user_struct(_user_struct_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _role json;
    _contacts json[];
    _res json;
BEGIN

    -- check if user_struct exists
    IF NOT EXISTS(SELECT * FROM user_struct WHERE id = _user_struct_id) THEN
        RAISE EXCEPTION 'No user_struct with id %d found', _user_struct_id USING ERRCODE = 'T5AZ0';
    end if;

    -- get role
    SELECT get_role(role_id) FROM user_struct WHERE id = _user_struct_id INTO _role;

    -- get contacts
    SELECT ARRAY(
       SELECT get_contact(id) FROM contact WHERE user_struct_id = _user_struct_id
    ) INTO _contacts;

    -- join in json
    SELECT INTO _res json_agg(x) -> 0 FROM (
        SELECT us.*, _role as role, _contacts as contacts FROM user_struct us WHERE id = _user_struct_id LIMIT 1
    ) x;

    RETURN _res;

END;
$function$

