CREATE OR REPLACE FUNCTION users.new_page(json_data json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    res json;
BEGIN

    -- check already exists
    IF EXISTS (SELECT * FROM page WHERE name = json_data ->> 'name') THEN
        RAISE EXCEPTION 'Page with name % already exists', json_data ->> 'name' USING ERRCODE = 'T2AZ1';
    end if;


    -- create page
    IF json_data ->> 'protected' IS NOT NULL THEN

        INSERT INTO page (name, parent, protected) values (json_data ->> 'name', json_data ->> 'parent', (json_data ->> 'protected')::bool);
    ELSE

        INSERT INTO page (name, parent) values (json_data ->> 'name', json_data ->> 'parent');
    end if;


    -- create res access
    if (json_data->'resources') IS NOT NULL THEN

        for res in select * from json_array_elements(json_data -> 'resources')
            loop
                PERFORM add_resource_access_to_page(json_data ->> 'name', res);
            end loop;
    END IF;
END;
$function$

