CREATE OR REPLACE FUNCTION users.new_role(json_data json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _role_id bigint;
    _page_name varchar;
BEGIN

    -- check does not shadow default
    IF EXISTS (SELECT * FROM role r WHERE r.name = json_data ->> 'name' AND r.customer_id IS NULL) THEN
        RAISE EXCEPTION 'Name % is already used by default role', json_data ->> 'name' USING ERRCODE = 'T3AZ1';
    end if;

    -- check already exists one with same (name, customer_id)
    IF EXISTS (SELECT * FROM role r WHERE r.name = json_data ->> 'name' AND r.customer_id = (json_data ->> 'customer_id')::bigint ) THEN
        RAISE EXCEPTION 'Page with name % already exists', json_data ->> 'name' USING ERRCODE = 'T3AZ1';
    end if;

    -- create role
    INSERT INTO role (name, customer_id, color) values (json_data ->> 'name', (json_data ->> 'customer_id')::bigint, json_data ->> 'color') RETURNING id INTO _role_id;

    -- add pages
    if (json_data->'pages') IS NOT NULL THEN

        for _page_name in select * from json_array_elements_text(json_data -> 'pages')
            loop

                PERFORM add_page_to_role(_role_id, _page_name);
            end loop;
    END IF;

    RETURN _role_id;
END;
$function$

CREATE OR REPLACE FUNCTION users.new_user_struct(json_data json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user_struct_id bigint;
    _active_user_struct_id bigint;
    _contact json;
    _enabled bool;
BEGIN

    -- check user_struct already exists
    IF EXISTS (SELECT * FROM user_struct us WHERE primary_email = json_data ->> 'email' AND customer_id = (json_data->>'customer_id')::bigint) THEN
        RAISE EXCEPTION 'user_struct [% , %] already exists', json_data ->> 'email', json_data->>'customer_id' USING ERRCODE = 'T5AZ1';
    end if;

    -- check role exists
    IF NOT EXISTS (SELECT * FROM role r WHERE id = (json_data ->> 'role_id')::bigint) THEN
        RAISE EXCEPTION 'No role with id %d found', (json_data ->> 'role_id')::bigint USING ERRCODE = 'T3AZ0';
    end if;

    -- create user if not exists
    PERFORM create_user_if_not_exists(json_data->>'email');

    IF json_data->>'enabled' IS NULL THEN
        _enabled = true;
    else
        _enabled = (json_data->>'enabled')::bool;
    end if;

    -- create user_struct
    INSERT INTO user_struct (customer_id, primary_email, first_name, last_name, role_id, marketing_on_primary_email, maintenance_on_primary_email, enabled, phone) VALUES (
        (json_data->>'customer_id')::bigint,
        json_data->>'email',
        json_data->>'first_name',
        json_data->>'last_name',
        (json_data->> 'role_id')::bigint,
        (json_data->>'marketing_on_primary_email')::bool,
        (json_data->>'maintenance_on_primary_email')::bool,
        _enabled,
        json_data->>'phone'
    ) RETURNING id INTO _user_struct_id;

    -- update pointer to active struct if null
    SELECT active_user_struct_id FROM "user" WHERE email = json_data->>'email' INTO _active_user_struct_id;
    IF _active_user_struct_id IS NULL THEN
        UPDATE "user" SET active_user_struct_id = _user_struct_id WHERE email = json_data->>'email';
    end if;

    -- create contacts
    if (json_data ->> 'contacts') IS NOT NULL THEN

        for _contact in select * from json_array_elements(json_data -> 'contacts')
            loop

                PERFORM add_contact_to_user_struct(_user_struct_id, _contact);
            end loop;
    END IF;

    RETURN _user_struct_id;
END;
$function$

CREATE OR REPLACE FUNCTION users.propagate_parent_selectable_on_update()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- set schema
    PERFORM set_config('search_path', TG_TABLE_SCHEMA, true);

