CREATE OR REPLACE FUNCTION users.update_page(json_data json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    res json;
BEGIN

    -- check if exist
    IF NOT EXISTS (SELECT * FROM page WHERE name = json_data ->> 'name') THEN
        RAISE EXCEPTION 'No page with name % found', json_data ->> 'name' USING ERRCODE = 'T2AZ0';
    end if;

    -- update parent
    IF json_data ->> 'parent' IS NOT NULL THEN
        UPDATE page SET parent = json_data ->> 'parent' WHERE name = json_data ->> 'name';

    END IF;

    -- update protected
    IF json_data ->> 'protected' IS NOT NULL THEN
        UPDATE page SET protected = (json_data ->> 'protected')::bool WHERE name = json_data ->> 'name';
    END IF;

    -- create res access if exists
    IF (json_data->'resources') IS NOT NULL THEN

        -- delete old
        DELETE FROM resource_access WHERE page_name = json_data ->> 'name';

        -- insert new
        for res in select * from json_array_elements(json_data -> 'resources')
        loop
            INSERT INTO resource_access (page_name, resource, access_type) VALUES (json_data ->> 'name', res ->> 'resource', res ->> 'access_type');
        end loop;
    END IF;
END;
$function$

