    PERFORM set_config('search_path', TG_TABLE_SCHEMA, true);

    -- if changed parent => update both parents
    IF OLD.selectable = true AND NEW.selectable = false THEN

        -- delete association between this page an any role that is not default
        DELETE FROM role_page WHERE page_name = NEW.name AND role_id IN (
            SELECT id FROM role WHERE customer_id IS NOT NULL
        );

    END IF;

    RETURN NEW;
