CREATE OR REPLACE FUNCTION users.update_selectable_on_update()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- set schema
    PERFORM set_config('search_path', TG_TABLE_SCHEMA, true);

    -- set selectable to not protected
    IF NEW.protected <> OLD.protected THEN

        IF NEW.protected= true THEN

            -- set current selectable=false
            NEW.selectable = false;
        ELSE

            -- compute current selectable value
            NEW.selectable = NOT has_protected_children(NEW.name);
        END IF;
    END IF;

    RETURN NEW;
END;
$function$

